mapper.insert:
INSERT INTO feed
SET location = #{location}
, contents = #{contents}
, user_id = #{SignedUserId}

mapper.select:
SELECT f.id, f.contents, f.location, f.created_at , u.id AS writerUserId , u.uid AS writerUid , u.nm AS writerNickName , u.pic AS writerPic FROM user u JOIN feed f ON f.user_id = u.id
WHERE f.user_id = #{profileUserId}
ORDER BY f.id DESC LIMIT #{startIdx}, #{size}

SELECT pic
FROM feed_pic
WHERE feed_id = #{id}
